// ─── Sub-components ──────────────────────────────────────────

interface KpiTileProps {
  label: string;
  value: number | null;
  suffix?: string;
}

function KpiTile({ label, value, suffix }: KpiTileProps): JSX.Element {
  return (
    <div className="landing-v2-kpi">
      <div className="landing-v2-kpi-label">{label}</div>
      <div className="landing-v2-kpi-value">
        {value === null ? (
          <span className="mono">—</span>
        ) : (
          <MonoNumber value={value} />
        )}
        {suffix ? <span className="landing-v2-kpi-suffix">{suffix}</span> : null}
      </div>
    </div>
  );
}

interface StepCardProps {
  n: number;
  title: string;
  body: string;
  link?: string;
}

function StepCard({ n, title, body, link }: StepCardProps): JSX.Element {
  const navigate = useNavigate();
  const interactive = Boolean(link);
  const onClick = link ? () => navigate(link) : undefined;

  return (
    <div
      className={`landing-v2-step ${interactive ? "landing-v2-step-interactive" : ""}`}
      onClick={onClick}
      role={interactive ? "button" : undefined}
      tabIndex={interactive ? 0 : undefined}
      onKeyDown={(e) => {
        if (interactive && (e.key === "Enter" || e.key === " ")) {
          e.preventDefault();
          onClick?.();
        }
      }}
    >
      <div className="landing-v2-step-n">
        <span className="mono">{String(n).padStart(2, "0")}</span>
      </div>
      <div className="landing-v2-step-body">
        <h3 className="landing-v2-step-title">{title}</h3>
        <p className="landing-v2-step-text">{body}</p>
        {link ? <div className="landing-v2-step-link">{link} →</div> : null}
      </div>
    </div>
  );
}

interface SafetyCardProps {
  badge: string;
  title: string;
  tagline: string;
  bullets: string[];
}

function SafetyCard({ badge, title, tagline, bullets }: SafetyCardProps): JSX.Element {
  return (
    <QuantGlowCard>
      <div className="landing-v2-safety-badge">{badge}</div>
      <h3 className="landing-v2-safety-title">{title}</h3>
      <p className="landing-v2-safety-tagline">{tagline}</p>
      <ul className="landing-v2-safety-bullets">
        {bullets.map((b) => (
          <li key={b}>{b}</li>
        ))}
      </ul>
    </QuantGlowCard>
  );
}

interface RoadmapCardProps {
  label: string;
  items: string[];
  kind?: "default" | "redline";
}

function RoadmapCard({ label, items, kind = "default" }: RoadmapCardProps): JSX.Element {
  return (
    <div className={`landing-v2-roadmap ${kind === "redline" ? "landing-v2-roadmap-redline" : ""}`}>
      <div className="landing-v2-roadmap-label">{label}</div>
      <ul className="landing-v2-roadmap-items">
        {items.map((it) => (
          <li key={it}>{it}</li>
        ))}
      </ul>
    </div>
  );
}
